import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // freq: 3->1, 1->2, 2->3  =>  [3, 1,1, 2,2,2]
        int[] result = new Solution().sortByFrequency(new int[]{1,1,2,2,2,3});
        assertArrayEquals(new int[]{3,1,1,2,2,2}, result);
    }

    @Test
    void tiebreakByValueDescending() {
        // all elements have freq=2; tiebreak desc value: 7,7,5,5,3,3
        int[] result = new Solution().sortByFrequency(new int[]{5,5,3,3,7,7});
        assertArrayEquals(new int[]{7,7,5,5,3,3}, result);
    }

    @Test
    void mixedFreqWithTie() {
        // freq: 3->1, 2->2, 1->2  =>  [3, 2,2, 1,1]  (freq=2 tiebreak: 2>1)
        int[] result = new Solution().sortByFrequency(new int[]{2,2,1,1,3});
        assertArrayEquals(new int[]{3,2,2,1,1}, result);
    }

    @Test
    void differentFrequencies() {
        // freq: 2->1, 1->2, 4->3  =>  [2, 1,1, 4,4,4]
        int[] result = new Solution().sortByFrequency(new int[]{4,4,4,1,1,2});
        assertArrayEquals(new int[]{2,1,1,4,4,4}, result);
    }

    @Test
    void singleElement() {
        int[] result = new Solution().sortByFrequency(new int[]{10});
        assertArrayEquals(new int[]{10}, result);
    }

    @Test
    void allSameElement() {
        // all elements identical — single group, order trivially preserved
        int[] result = new Solution().sortByFrequency(new int[]{7,7,7});
        assertArrayEquals(new int[]{7,7,7}, result);
    }

    @Test
    void empty() {
        int[] result = new Solution().sortByFrequency(new int[]{});
        assertArrayEquals(new int[]{}, result);
    }
}
